import{_ as a,o as s,c as n,ag as t}from"./chunks/framework.DXzMPhrv.js";const u=JSON.parse('{"title":"Architecture","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"guide/architecture.md","filePath":"guide/architecture.md","lastUpdated":1773692010000}'),i={name:"guide/architecture.md"};function o(r,e,l,c,p,d){return s(),n("div",null,[...e[0]||(e[0]=[t(`<h1 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h1><h2 id="table-of-contents" tabindex="-1">Table of Contents <a class="header-anchor" href="#table-of-contents" aria-label="Permalink to &quot;Table of Contents&quot;">​</a></h2><ul><li><a href="#overview">Overview</a></li><li><a href="#design-principles">Design Principles</a></li><li><a href="#component-diagram">Component Diagram</a></li><li><a href="#plugin-system">Plugin System</a></li><li><a href="#data-flow">Data Flow</a></li><li><a href="#dotnotationparser-engine">DotNotationParser Engine</a></li><li><a href="#immutability-pattern">Immutability Pattern</a></li><li><a href="#typedetector">TypeDetector</a></li><li><a href="#monorepo-structure">Monorepo Structure</a></li><li><a href="#security-architecture">Security Architecture</a></li><li><a href="#io--file-loading">I/O &amp; File Loading</a></li><li><a href="#schema-validation">Schema Validation</a></li><li><a href="#audit-system">Audit System</a></li><li><a href="#cli-package">CLI Package</a></li><li><a href="#framework-integrations">Framework Integrations</a></li><li><a href="#architecture-decision-records">Architecture Decision Records</a></li></ul><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>safe-access-inline is a format-agnostic data access library that provides a single API for safely reading, writing, and transforming deeply nested data structures. It follows the <strong>Facade pattern</strong> with a pluggable accessor system and an extensible <strong>Plugin Registry</strong> for format parsing and serialization.</p><h2 id="design-principles" tabindex="-1">Design Principles <a class="header-anchor" href="#design-principles" aria-label="Permalink to &quot;Design Principles&quot;">​</a></h2><ol><li><strong>Zero Surprises</strong> — <code>get()</code> never throws exceptions. Missing paths return a default value.</li><li><strong>Format-Agnostic</strong> — The same API works identically across all supported formats.</li><li><strong>Immutability</strong> — <code>set()</code> and <code>remove()</code> always return new instances; the original is never mutated.</li><li><strong>Real Dependencies for Complex Formats</strong> — YAML and TOML use real libraries (<code>js-yaml</code>/<code>smol-toml</code> in JS, <code>symfony/yaml</code>/<code>devium/toml</code> in PHP) as dependencies. The Plugin System provides optional override capability.</li><li><strong>Extensibility</strong> — Custom accessors via <code>SafeAccess::extend()</code>, custom parsers and serializers via <code>PluginRegistry</code>.</li></ol><h2 id="component-diagram" tabindex="-1">Component Diagram <a class="header-anchor" href="#component-diagram" aria-label="Permalink to &quot;Component Diagram&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────┐</span></span>
<span class="line"><span>│       SafeAccess Facade      │  ← Static entry point</span></span>
<span class="line"><span>│  fromArray / fromJson / ...  │</span></span>
<span class="line"><span>│  detect / extend / custom    │</span></span>
<span class="line"><span>└──────────┬───────────────────┘</span></span>
<span class="line"><span>           │ creates</span></span>
<span class="line"><span>           ▼</span></span>
<span class="line"><span>┌──────────────────────────────┐</span></span>
<span class="line"><span>│     AbstractAccessor         │  ← Base class (all logic)</span></span>
<span class="line"><span>│  get / set / remove / has    │</span></span>
<span class="line"><span>│  toArray / toJson / toXml    │</span></span>
<span class="line"><span>│  toYaml / toToml / transform │</span></span>
<span class="line"><span>│  type / count / keys / all   │</span></span>
<span class="line"><span>│  push / pop / shift / insert │  ← Array operations</span></span>
<span class="line"><span>│  diff / applyPatch           │  ← JSON Patch (RFC 6902)</span></span>
<span class="line"><span>│  masked / validate           │  ← Security &amp; schema</span></span>
<span class="line"><span>└──────────┬───────────────────┘</span></span>
<span class="line"><span>           │</span></span>
<span class="line"><span>     ┌─────┴─────────────────────┐</span></span>
<span class="line"><span>     │ delegates path            │ delegates serialization</span></span>
<span class="line"><span>     │ resolution to             │ &amp; parsing to</span></span>
<span class="line"><span>     ▼                           ▼</span></span>
<span class="line"><span>┌────────────────────┐   ┌────────────────────────┐</span></span>
<span class="line"><span>│  DotNotationParser │   │    PluginRegistry       │</span></span>
<span class="line"><span>│  get / has / set   │   │  registerParser()       │</span></span>
<span class="line"><span>│  remove / parseKeys│   │  registerSerializer()   │</span></span>
<span class="line"><span>│  buildPath         │   │  getParser / has / get  │</span></span>
<span class="line"><span>└────────────────────┘   └────────┬───────────────┘</span></span>
<span class="line"><span>                                  │ stores</span></span>
<span class="line"><span>                     ┌────────────┼────────────────┐</span></span>
<span class="line"><span>                     ▼            ▼                ▼</span></span>
<span class="line"><span>              ┌───────────┐ ┌──────────────┐ ┌──────────┐</span></span>
<span class="line"><span>              │  Parsers   │ │ Serializers  │ │ Custom   │</span></span>
<span class="line"><span>              │  yaml,toml │ │ yaml,xml,... │ │ plugins  │</span></span>
<span class="line"><span>              └───────────┘ └──────────────┘ └──────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Concrete Accessors (extend AbstractAccessor):</span></span>
<span class="line"><span>┌──────────┬──────────┬──────────┐</span></span>
<span class="line"><span>│  Array   │  Object  │  JSON    │</span></span>
<span class="line"><span>│  XML     │  YAML    │  TOML    │</span></span>
<span class="line"><span>│  INI     │  CSV     │  ENV     │</span></span>
<span class="line"><span>│  NDJSON  │          │          │</span></span>
<span class="line"><span>└──────────┴──────────┴──────────┘</span></span>
<span class="line"><span>Each only implements: parse(raw) → array</span></span>
<span class="line"><span>(YAML/TOML use real libraries by default, with optional PluginRegistry override)</span></span></code></pre></div><h2 id="plugin-system" tabindex="-1">Plugin System <a class="header-anchor" href="#plugin-system" aria-label="Permalink to &quot;Plugin System&quot;">​</a></h2><p>The Plugin System provides <strong>optional override</strong> capability for format-specific parsing and serialization. YAML and TOML use real libraries by default — plugins let users swap in alternative implementations.</p><h3 id="contracts" tabindex="-1">Contracts <a class="header-anchor" href="#contracts" aria-label="Permalink to &quot;Contracts&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌───────────────────────────┐     ┌───────────────────────────────┐</span></span>
<span class="line"><span>│  ParserPluginInterface    │     │  SerializerPluginInterface    │</span></span>
<span class="line"><span>│  parse(string): array     │     │  serialize(array): string     │</span></span>
<span class="line"><span>└───────────────────────────┘     └───────────────────────────────┘</span></span></code></pre></div><ul><li><strong><code>ParserPluginInterface</code></strong> — receives a raw string input (e.g., YAML text), returns a normalized associative array. Throws <code>InvalidFormatException</code> on malformed input.</li><li><strong><code>SerializerPluginInterface</code></strong> — receives a normalized array, returns a formatted string output (e.g., YAML text).</li></ul><h3 id="pluginregistry" tabindex="-1">PluginRegistry <a class="header-anchor" href="#pluginregistry" aria-label="Permalink to &quot;PluginRegistry&quot;">​</a></h3><p>A static registry that maps format names (e.g., <code>&#39;yaml&#39;</code>, <code>&#39;toml&#39;</code>) to parser and serializer implementations.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>PluginRegistry::registerParser(&#39;yaml&#39;, new SymfonyYamlParser());</span></span>
<span class="line"><span>PluginRegistry::registerSerializer(&#39;yaml&#39;, new SymfonyYamlSerializer());</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Accessors query the registry:</span></span>
<span class="line"><span>// YamlAccessor::parse() → PluginRegistry::getParser(&#39;yaml&#39;)-&gt;parse($raw)</span></span>
<span class="line"><span>// $accessor-&gt;toYaml()   → PluginRegistry::getSerializer(&#39;yaml&#39;)-&gt;serialize($data)</span></span>
<span class="line"><span>// $accessor-&gt;transform(&#39;yaml&#39;) → same as toYaml()</span></span></code></pre></div><h3 id="php-vs-js-behavior" tabindex="-1">PHP vs JS Behavior <a class="header-anchor" href="#php-vs-js-behavior" aria-label="Permalink to &quot;PHP vs JS Behavior&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Aspect</th><th>PHP</th><th>JS/TS</th></tr></thead><tbody><tr><td>YAML/TOML parsing</td><td>Real library by default (<code>ext-yaml</code> or <code>symfony/yaml</code> for YAML, <code>devium/toml</code> for TOML); plugin <strong>optional</strong> (overrides)</td><td>Real library by default (<code>js-yaml</code>, <code>smol-toml</code>); plugin <strong>optional</strong> (overrides)</td></tr><tr><td>Serialization (<code>toYaml</code>, <code>toToml</code>, <code>toXml</code>, <code>transform</code>)</td><td>Plugin override → <code>ext-yaml</code>/real library fallback (with <code>SimpleXMLElement</code> fallback for XML)</td><td>Real library by default for YAML/TOML; plugin required for XML</td></tr><tr><td>Shipped plugins</td><td>6 plugins (SymfonyYamlParser, SymfonyYamlSerializer, NativeYamlParser, NativeYamlSerializer, DeviumTomlParser, DeviumTomlSerializer)</td><td>4 plugins (JsYamlParser, JsYamlSerializer, SmolTomlParser, SmolTomlSerializer)</td></tr></tbody></table><h2 id="data-flow" tabindex="-1">Data Flow <a class="header-anchor" href="#data-flow" aria-label="Permalink to &quot;Data Flow&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Input (string/array/object)</span></span>
<span class="line"><span>  → Accessor::from(data)</span></span>
<span class="line"><span>    → Constructor: raw = data, data = parse(raw)</span></span>
<span class="line"><span>      → For most formats: accessor-specific parsing (JSON.parse, XML parse, etc.)</span></span>
<span class="line"><span>      → For YAML (PHP): PluginRegistry override → ext-yaml (yaml_parse) → Symfony\\Yaml fallback</span></span>
<span class="line"><span>      → For TOML (PHP): PluginRegistry override → Devium\\Toml default</span></span>
<span class="line"><span>      → For YAML/TOML (JS): PluginRegistry override → real library default (js-yaml / smol-toml)</span></span>
<span class="line"><span>  → Normalized array stored in $data / this.data</span></span>
<span class="line"><span>  → All read operations (get/set/has/etc.) operate on data via DotNotationParser</span></span>
<span class="line"><span>  → Transformation methods:</span></span>
<span class="line"><span>      → toArray() / toJson() / toObject() — built-in, always available</span></span>
<span class="line"><span>      → toXml() — built-in in PHP (SimpleXMLElement), plugin-based in JS</span></span>
<span class="line"><span>      → toYaml() — Plugin override → ext-yaml (yaml_emit) → symfony/yaml fallback in PHP; js-yaml default in JS</span></span>
<span class="line"><span>      → toToml() — Plugin override → devium/toml default in PHP; smol-toml default in JS</span></span>
<span class="line"><span>      → transform(format) — always delegates to PluginRegistry::getSerializer(format)</span></span></code></pre></div><h2 id="dotnotationparser-engine" tabindex="-1">DotNotationParser Engine <a class="header-anchor" href="#dotnotationparser-engine" aria-label="Permalink to &quot;DotNotationParser Engine&quot;">​</a></h2><p>The parser resolves paths like <code>user.profile.name</code> against nested data structures.</p><p><strong>Supported path syntax:</strong></p><ul><li><code>name</code> — simple key access</li><li><code>user.profile.name</code> — nested access</li><li><code>items.0.title</code> — numeric index access</li><li><code>matrix[0][1]</code> — bracket notation (converted to dot notation)</li><li><code>users.*.name</code> — wildcard (returns array of all matching values)</li><li><code>config\\.db.host</code> — escaped dot (literal dot in key name)</li></ul><p><strong>Resolution algorithm:</strong></p><ol><li>Parse path into key segments via <code>parseKeys()</code></li><li>Walk the data structure segment by segment</li><li>On <code>*</code> wildcard: iterate all children, recursively resolve remaining path</li><li>On escaped dot: treat as literal key name</li><li>Return default value if any segment is not found</li></ol><h2 id="immutability-pattern" tabindex="-1">Immutability Pattern <a class="header-anchor" href="#immutability-pattern" aria-label="Permalink to &quot;Immutability Pattern&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$original = SafeAccess::fromJson(&#39;{&quot;a&quot;: 1}&#39;);</span></span>
<span class="line"><span>$modified = $original-&gt;set(&#39;b&#39;, 2);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// $original-&gt;data = [&#39;a&#39; =&gt; 1]     ← unchanged</span></span>
<span class="line"><span>// $modified-&gt;data = [&#39;a&#39; =&gt; 1, &#39;b&#39; =&gt; 2]  ← new instance</span></span></code></pre></div><p>Implementation:</p><ul><li>PHP: <code>clone $this</code> + update <code>$data</code></li><li>JS: <code>clone(newData)</code> method creates a new instance with modified data (via <code>structuredClone</code>)</li></ul><h2 id="typedetector" tabindex="-1">TypeDetector <a class="header-anchor" href="#typedetector" aria-label="Permalink to &quot;TypeDetector&quot;">​</a></h2><p>Auto-detection priority (first match wins):</p><ol><li><strong>Array</strong> → <code>ArrayAccessor</code></li><li><strong>SimpleXMLElement</strong> (PHP only) → <code>XmlAccessor</code></li><li><strong>Object</strong> → <code>ObjectAccessor</code></li><li><strong>JSON string</strong> (<code>{</code> or <code>[</code>) → <code>JsonAccessor</code></li><li><strong>NDJSON string</strong> (multiple <code>{...}</code> lines) → <code>NdjsonAccessor</code></li><li><strong>XML string</strong> (<code>&lt;?xml</code> or <code>&lt;</code>) → <code>XmlAccessor</code></li><li><strong>YAML string</strong> (contains <code>: </code> value pairs or <code>---</code> front-matter) → <code>YamlAccessor</code></li><li><strong>INI string</strong> (has <code>[section]</code> or <code>key = value</code>) → <code>IniAccessor</code></li><li><strong>ENV string</strong> (<code>KEY=VALUE</code> pattern) → <code>EnvAccessor</code></li><li><strong>Unsupported</strong> → throws <code>UnsupportedTypeError</code> / <code>UnsupportedTypeException</code></li></ol><blockquote><p><strong>Limitations:</strong> TOML and CSV are not auto-detected due to format ambiguity. The YAML heuristic (<code>key:</code> pattern without <code>=</code>) may produce false positives for non-YAML strings. Always prefer explicit factory methods (e.g., <code>fromYaml()</code>, <code>fromToml()</code>) for ambiguous inputs.</p></blockquote><h2 id="monorepo-structure" tabindex="-1">Monorepo Structure <a class="header-anchor" href="#monorepo-structure" aria-label="Permalink to &quot;Monorepo Structure&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>safe-access-inline/</span></span>
<span class="line"><span>├── packages/</span></span>
<span class="line"><span>│   ├── php/                 # Composer package</span></span>
<span class="line"><span>│   │   ├── src/</span></span>
<span class="line"><span>│   │   │   ├── Accessors/   # 10 format accessors (incl. NDJSON)</span></span>
<span class="line"><span>│   │   │   ├── Contracts/   # Interfaces (incl. ParserPlugin, SerializerPlugin, SchemaAdapter)</span></span>
<span class="line"><span>│   │   │   ├── Core/        # AbstractAccessor, DotNotationParser, PathCache, TypeDetector, PluginRegistry, SchemaRegistry, JsonPatch, IoLoader, FileWatcher, DeepMerger</span></span>
<span class="line"><span>│   │   │   ├── Enums/       # AccessorFormat enum</span></span>
<span class="line"><span>│   │   │   ├── Exceptions/  # Exception hierarchy (incl. SecurityException, SchemaValidationException, ReadonlyViolationException)</span></span>
<span class="line"><span>│   │   │   ├── Integrations/# LaravelServiceProvider, SymfonyIntegration</span></span>
<span class="line"><span>│   │   │   ├── Plugins/     # Shipped plugins (SymfonyYaml*, NativeYaml*, DeviumToml*)</span></span>
<span class="line"><span>│   │   │   ├── Security/    # SecurityPolicy, SecurityOptions, SecurityGuard, CsvSanitizer, DataMasker, AuditLogger</span></span>
<span class="line"><span>│   │   │   ├── Traits/      # HasFactory, HasTransformations, HasWildcardSupport</span></span>
<span class="line"><span>│   │   │   └── SafeAccess.php</span></span>
<span class="line"><span>│   │   └── tests/</span></span>
<span class="line"><span>│   │       ├── Unit/        # Mock-based unit tests</span></span>
<span class="line"><span>│   │       └── Integration/ # Real parser integration tests</span></span>
<span class="line"><span>│   ├── js/                  # npm package</span></span>
<span class="line"><span>│   │   ├── src/</span></span>
<span class="line"><span>│   │   │   ├── accessors/   # 10 format accessors (incl. NDJSON)</span></span>
<span class="line"><span>│   │   │   ├── contracts/   # TypeScript interfaces</span></span>
<span class="line"><span>│   │   │   ├── core/        # AbstractAccessor, DotNotationParser, PathCache, TypeDetector, PluginRegistry, SchemaRegistry, JsonPatch, IoLoader, FileWatcher, DeepMerger, AuditEmitter</span></span>
<span class="line"><span>│   │   │   ├── exceptions/  # Error hierarchy (incl. SecurityError, SchemaValidationError, ReadonlyViolationError)</span></span>
<span class="line"><span>│   │   │   ├── integrations/# NestJS module, Vite plugin</span></span>
<span class="line"><span>│   │   │   ├── plugins/     # Shipped plugins (JsYaml*, SmolToml*)</span></span>
<span class="line"><span>│   │   │   ├── types/       # DeepPaths, ValueAtPath utility types</span></span>
<span class="line"><span>│   │   │   ├── safe-access.ts</span></span>
<span class="line"><span>│   │   │   └── index.ts     # Barrel export</span></span>
<span class="line"><span>│   │   └── tests/</span></span>
<span class="line"><span>│   │       ├── unit/        # Mock-based unit tests</span></span>
<span class="line"><span>│   │       └── integration/ # Cross-format pipeline tests</span></span>
<span class="line"><span>│   └── cli/                 # CLI package (@safe-access-inline/cli)</span></span>
<span class="line"><span>│       ├── src/cli.ts       # CLI entry point (get, set, remove, transform, diff, mask, layer, keys, type, has, count)</span></span>
<span class="line"><span>│       └── tests/</span></span>
<span class="line"><span>├── docs/                    # Documentation (Jekyll, English + pt-BR)</span></span>
<span class="line"><span>├── .github/workflows/       # CI/CD</span></span>
<span class="line"><span>├── CHANGELOG.md</span></span>
<span class="line"><span>├── CODE_OF_CONDUCT.md</span></span>
<span class="line"><span>├── CONTRIBUTING.md</span></span>
<span class="line"><span>├── LICENSE</span></span>
<span class="line"><span>├── SECURITY.md</span></span>
<span class="line"><span>└── README.md</span></span></code></pre></div><h2 id="security-architecture" tabindex="-1">Security Architecture <a class="header-anchor" href="#security-architecture" aria-label="Permalink to &quot;Security Architecture&quot;">​</a></h2><p>The security module provides defense-in-depth for data processing:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                    SecurityPolicy                       │</span></span>
<span class="line"><span>│  maxDepth, maxPayloadBytes, maxKeys, allowedDirs,       │</span></span>
<span class="line"><span>│  url options, csvMode, maskPatterns                     │</span></span>
<span class="line"><span>└──────────┬──────────────────────────────────────────────┘</span></span>
<span class="line"><span>           │ delegates to</span></span>
<span class="line"><span>     ┌─────┴─────────┬──────────────┬────────────────┐</span></span>
<span class="line"><span>     ▼               ▼              ▼                ▼</span></span>
<span class="line"><span>┌──────────┐  ┌──────────────┐ ┌───────────┐  ┌───────────┐</span></span>
<span class="line"><span>│ Security │  │    IoLoader   │ │   CSV     │  │   Data    │</span></span>
<span class="line"><span>│ Options  │  │  path/URL    │ │ Sanitizer │  │  Masker   │</span></span>
<span class="line"><span>│ (limits) │  │  validation  │ │           │  │           │</span></span>
<span class="line"><span>└──────────┘  └──────────────┘ └───────────┘  └───────────┘</span></span></code></pre></div><ul><li><strong>SecurityPolicy</strong> — Immutable aggregate of all security settings. Supports <code>merge()</code> for creating derived policies.</li><li><strong>SecurityOptions</strong> — Static assertion methods for payload size, key count, and nesting depth limits.</li><li><strong>SecurityGuard</strong> — Blocks prototype pollution keys (<code>__proto__</code>, <code>constructor</code>, <code>prototype</code>, <code>__defineGetter__</code>, <code>__defineSetter__</code>, <code>__lookupGetter__</code>, <code>__lookupSetter__</code>, <code>valueOf</code>, <code>toString</code>, <code>hasOwnProperty</code>, <code>isPrototypeOf</code>). Sanitizes objects recursively.</li><li><strong>IoLoader</strong> — Path-traversal protection for file reads. SSRF protection for URL fetches (blocks private IPs, cloud metadata, enforces HTTPS).</li><li><strong>CsvSanitizer</strong> — Guards against CSV injection attacks with configurable modes (none, prefix, strip, error).</li><li><strong>DataMasker</strong> — Replaces sensitive values (password, token, secret, etc.) with <code>[REDACTED]</code>. Supports custom glob/regex patterns.</li></ul><h2 id="i-o-file-loading" tabindex="-1">I/O &amp; File Loading <a class="header-anchor" href="#i-o-file-loading" aria-label="Permalink to &quot;I/O &amp; File Loading&quot;">​</a></h2><p>File and URL loading follow a secure pipeline:</p><ol><li><strong>Path validation</strong> — Resolved path must be within <code>allowedDirs</code> (if specified)</li><li><strong>Format detection</strong> — Extension-based (<code>resolveFormatFromExtension</code>)</li><li><strong>Content reading</strong> — File system or HTTPS fetch</li><li><strong>Audit emission</strong> — <code>file.read</code> or <code>url.fetch</code> event</li><li><strong>Accessor creation</strong> — Delegated to the appropriate <code>SafeAccess.from*()</code> method</li></ol><p>File watching uses polling (<code>FileWatcher</code>) — checks mtime at configurable intervals. Returns a stop function for cleanup.</p><ul><li><strong>PathCache</strong> — LRU in-memory cache layered between <code>AbstractAccessor</code> and <code>DotNotationParser</code>. Parsed path segment arrays are stored keyed by path string, eliminating redundant re-parsing on repeated hot-path accesses.</li></ul><p>Layered configuration (<code>layer()</code>, <code>layerFiles()</code>) deep-merges multiple sources with last-wins semantics.</p><h2 id="schema-validation" tabindex="-1">Schema Validation <a class="header-anchor" href="#schema-validation" aria-label="Permalink to &quot;Schema Validation&quot;">​</a></h2><p>Schema validation uses the <strong>Adapter pattern</strong> to remain library-agnostic:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌───────────────────┐     ┌────────────────────────┐</span></span>
<span class="line"><span>│  SchemaRegistry   │────▶│  SchemaAdapterInterface │</span></span>
<span class="line"><span>│  default adapter  │     │  validate(data, schema) │</span></span>
<span class="line"><span>└───────────────────┘     └────────────┬───────────┘</span></span>
<span class="line"><span>                                       │ returns</span></span>
<span class="line"><span>                                       ▼</span></span>
<span class="line"><span>                          ┌────────────────────────┐</span></span>
<span class="line"><span>                          │ SchemaValidationResult  │</span></span>
<span class="line"><span>                          │  valid: bool            │</span></span>
<span class="line"><span>                          │  errors: Issue[]        │</span></span>
<span class="line"><span>                          └────────────────────────┘</span></span></code></pre></div><p>Users implement <code>SchemaAdapterInterface</code> with their preferred validation library (Zod, Joi, JSON Schema, etc.) and register it via <code>SchemaRegistry.setDefaultAdapter()</code>.</p><h2 id="audit-system" tabindex="-1">Audit System <a class="header-anchor" href="#audit-system" aria-label="Permalink to &quot;Audit System&quot;">​</a></h2><p>The audit system provides observability for security-relevant operations:</p><ul><li><strong>Event types:</strong> <code>file.read</code>, <code>file.watch</code>, <code>url.fetch</code>, <code>security.violation</code>, <code>data.mask</code>, <code>data.freeze</code>, <code>schema.validate</code></li><li><strong>Subscription:</strong> <code>SafeAccess.onAudit(listener)</code> returns an unsubscribe function</li><li><strong>Emission:</strong> Internal — triggered automatically by IoLoader, DataMasker, schema validation, etc.</li><li><strong>Design:</strong> Pub/sub pattern. Listeners are synchronous. Events include <code>type</code>, <code>timestamp</code>, and <code>detail</code> fields.</li></ul><h2 id="cli-package" tabindex="-1">CLI Package <a class="header-anchor" href="#cli-package" aria-label="Permalink to &quot;CLI Package&quot;">​</a></h2><p>The <code>@safe-access-inline/cli</code> package provides command-line access to all library features:</p><table tabindex="0"><thead><tr><th>Command</th><th>Description</th></tr></thead><tbody><tr><td><code>get</code></td><td>Read a value by path</td></tr><tr><td><code>set</code></td><td>Set a value at a path</td></tr><tr><td><code>remove</code></td><td>Remove a value at a path</td></tr><tr><td><code>transform</code></td><td>Convert between formats (JSON ↔ YAML ↔ TOML)</td></tr><tr><td><code>diff</code></td><td>Generate JSON Patch diff between two files</td></tr><tr><td><code>mask</code></td><td>Redact sensitive values</td></tr><tr><td><code>layer</code></td><td>Merge multiple config files</td></tr><tr><td><code>keys</code></td><td>List keys at a path</td></tr><tr><td><code>type</code></td><td>Show the type of a value at a path</td></tr><tr><td><code>has</code></td><td>Check path existence (exit code 0/1)</td></tr><tr><td><code>count</code></td><td>Count elements at a path</td></tr></tbody></table><p>Supports stdin input (<code>-</code>), all formats (JSON, YAML, TOML, XML, INI, CSV, ENV, NDJSON), pretty output, and path expressions.</p><h2 id="framework-integrations" tabindex="-1">Framework Integrations <a class="header-anchor" href="#framework-integrations" aria-label="Permalink to &quot;Framework Integrations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Framework</th><th>Package</th><th>Module</th><th>Features</th></tr></thead><tbody><tr><td>NestJS</td><td>JS</td><td><code>SafeAccessModule</code></td><td>Dynamic module, <code>SAFE_ACCESS</code> injection token</td></tr><tr><td>Vite</td><td>JS</td><td><code>safeAccessPlugin</code></td><td>Virtual module, HMR support, multi-file merging</td></tr><tr><td>Laravel</td><td>PHP</td><td><code>LaravelServiceProvider</code></td><td>Singleton binding, config repository wrapping</td></tr><tr><td>Symfony</td><td>PHP</td><td><code>SymfonyIntegration</code></td><td>ParameterBag wrapping, YAML file loading</td></tr></tbody></table><h2 id="architecture-decision-records" tabindex="-1">Architecture Decision Records <a class="header-anchor" href="#architecture-decision-records" aria-label="Permalink to &quot;Architecture Decision Records&quot;">​</a></h2><h3 id="adr-1-set-remove-use-clone-instead-of-static-from" tabindex="-1">ADR-1: <code>set()</code> / <code>remove()</code> use <code>clone</code> instead of <code>static::from()</code> <a class="header-anchor" href="#adr-1-set-remove-use-clone-instead-of-static-from" aria-label="Permalink to &quot;ADR-1: \`set()\` / \`remove()\` use \`clone\` instead of \`static::from()\`&quot;">​</a></h3><p><strong>Context:</strong> The PLAN.md specifies <code>set()</code> returns <code>static::from($newData)</code>. However, some accessors carry metadata beyond the normalized array — for example, <code>XmlAccessor</code> stores the <code>originalXml</code> string.</p><p><strong>Decision:</strong> Both PHP and JS use <code>clone</code> (PHP: <code>clone $this</code>; JS: <code>clone(newData)</code> method) to preserve any accessor-specific metadata when producing a new instance. Only <code>$data</code> is updated.</p><p><strong>Consequence:</strong> Metadata like <code>originalXml</code> survives mutations, which is the expected behavior. The round-trip <code>set() → toXml()</code> can still access the original XML via <code>getOriginalXml()</code>.</p><h3 id="adr-2-js-toxml-toyaml-totoml-via-real-libraries-plugin-override" tabindex="-1">ADR-2: JS <code>toXml()</code> / <code>toYaml()</code> / <code>toToml()</code> via Real Libraries + Plugin Override <a class="header-anchor" href="#adr-2-js-toxml-toyaml-totoml-via-real-libraries-plugin-override" aria-label="Permalink to &quot;ADR-2: JS \`toXml()\` / \`toYaml()\` / \`toToml()\` via Real Libraries + Plugin Override&quot;">​</a></h3><p><strong>Context:</strong> Initially, the JS package omitted <code>toXml()</code> and <code>toYaml()</code> because JavaScript has no native XML emitter and YAML serialization would require a runtime dependency.</p><p><strong>Decision (original):</strong> JS only exposed <code>toArray()</code>, <code>toJson()</code>, and <code>toObject()</code>.</p><p><strong>Decision (revised #1):</strong> With the introduction of the Plugin System, JS exposed <code>toYaml()</code>, <code>toXml()</code>, and <code>transform()</code> via PluginRegistry.</p><p><strong>Decision (revised #2):</strong> <code>js-yaml</code> and <code>smol-toml</code> are now real <code>dependencies</code>. <code>toYaml()</code> and <code>toToml()</code> work zero-config using these libraries. Plugins provide optional override for users who need different libraries. <code>toXml()</code> still requires a plugin.</p><p><strong>Consequence:</strong> YAML and TOML serialization works out of the box. Users who need alternative serializers register a plugin override. XML serialization still requires explicit plugin registration.</p><h3 id="adr-3-real-dependencies-for-yaml-toml-pluginregistry-for-override" tabindex="-1">ADR-3: Real Dependencies for YAML/TOML + PluginRegistry for Override <a class="header-anchor" href="#adr-3-real-dependencies-for-yaml-toml-pluginregistry-for-override" aria-label="Permalink to &quot;ADR-3: Real Dependencies for YAML/TOML + PluginRegistry for Override&quot;">​</a></h3><p><strong>Context:</strong> PHP&#39;s YAML and TOML accessors originally used <code>class_exists()</code> and <code>function_exists()</code> checks to detect available parsers at runtime. Later, a PluginRegistry was introduced that required manual plugin registration. Both PHP and JS had different approaches: PHP required plugins, JS had built-in lightweight parsers.</p><p><strong>Decision:</strong> Make YAML/TOML libraries real dependencies in both platforms. <code>js-yaml</code> + <code>smol-toml</code> are <code>dependencies</code> in JS. <code>symfony/yaml</code> + <code>devium/toml</code> are <code>require</code> in PHP. PluginRegistry continues to exist for override: if a plugin is registered, it takes priority over the default library.</p><p><strong>Key design choices:</strong></p><ul><li><strong>Both platforms</strong>: YAML/TOML parsing and serialization work out of the box — zero configuration needed.</li><li><strong>Plugin override</strong>: <code>PluginRegistry.registerParser()</code> / <code>PluginRegistry.registerSerializer()</code> still works — registered plugins take priority over default libraries.</li><li><strong>JS built-in parsers removed</strong>: The old lightweight YAML/TOML parsers were removed in favor of proven libraries (<code>js-yaml</code>, <code>smol-toml</code>).</li><li><strong>Exception types</strong>: <code>InvalidFormatException</code> at the accessor level, <code>UnsupportedTypeException</code> at the registry level.</li><li><strong>Testing</strong>: Unit tests use mock plugins (anonymous classes/objects) for isolation. Integration tests use real libraries.</li></ul><p><strong>Consequence:</strong> Zero configuration for YAML/TOML in both platforms. Consistent behavior between PHP and JS. Users who need alternative parsers/serializers register them via PluginRegistry.</p>`,77)])])}const m=a(i,[["render",o]]);export{u as __pageData,m as default};
